/* snolib.plsw -- SNOBOL4 runtime library
 *
 * Descriptor and heap header helper procedures.
 * This file is the runtime core used by all SNOBOL4 programs.
 */

%INCLUDE descr;
%INCLUDE heap;
%INCLUDE trace;

/* ================================================================
 * Descriptor construction
 * ================================================================ */

/* DESC_SET: initialize a descriptor at pointer P */
DESC_SET: PROC(P PTR, T BYTE, S BYTE, V INT);
    DCL DP PTR;
    DP = P;
    DP->DTAG = T;
    DP->DSUB = S;
    DP->DRSV = 0;
    DP->DPAY = V;
END;

/* DESC_SET_NULL: set descriptor to null */
DESC_SET_NULL: PROC(P PTR);
    DCL DP PTR;
    DP = P;
    DP->DTAG = TAG_NULL;
    DP->DSUB = 0;

